/* Iterative binary search */
int binarySearch(int arr[], int n, int target) {
    int low = 0, high = n - 1;

    while (low <= high) {
        int mid = low + (high - low) / 2;  /* overflow-safe */

        if (arr[mid] == target)
            return mid;
        else if (arr[mid] < target)
            low = mid + 1;
        else
            high = mid - 1;
    }
    return -1;  /* not found */
}

/* Recursive binary search */
int binarySearchRecursive(int arr[], int low, int high, int target) {
    if (low > high)
        return -1;

    int mid = low + (high - low) / 2;

    if (arr[mid] == target)
        return mid;
    else if (arr[mid] < target)
        return binarySearchRecursive(arr, mid + 1, high, target);
    else
        return binarySearchRecursive(arr, low, mid - 1, target);
}

int main(void) {
    int arr[] = {2, 3, 4, 10, 40, 50, 70};
    int n = sizeof(arr) / sizeof(arr[0]);

    int idx = binarySearch(arr, n, 10);
    printf("Found 10 at index: %d\n", idx);  /* 3 */

    idx = binarySearch(arr, n, 5);
    printf("Found 5 at index: %d\n", idx);   /* -1 */

    idx = binarySearchRecursive(arr, 0, n - 1, 40);
    printf("Found 40 at index: %d\n", idx);  /* 4 */

    return 0;
}

