/* Sentinel linear search (eliminates bounds check) */
int sentinelSearch(int arr[], int n, int target) {
    int last = arr[n - 1];
    arr[n - 1] = target;  /* place sentinel */

    int i = 0;
    while (arr[i] != target)  /* no bounds check needed */
        i++;

    arr[n - 1] = last;  /* restore original value */

    if (i < n - 1 || arr[n - 1] == target)
        return i;
    return -1;
}

