/* Quick sort with tail recursion optimization: O(log n) stack */
void swap(int *a, int *b) { int t = *a; *a = *b; *b = t; }

int partition(int arr[], int lo, int hi) {
    int pivot = arr[hi], i = lo - 1;
    for (int j = lo; j < hi; j++)
        if (arr[j] <= pivot) swap(&arr[++i], &arr[j]);
    swap(&arr[i + 1], &arr[hi]);
    return i + 1;
}

/* Tail-call optimized: always recurse on smaller half */
void quicksortOptimized(int arr[], int lo, int hi) {
    while (lo < hi) {
        int p = partition(arr, lo, hi);
        /* Recurse on smaller half, iterate on larger */
        if (p - lo < hi - p) {
            quicksortOptimized(arr, lo, p - 1);
            lo = p + 1;  /* tail call elimination */
        } else {
            quicksortOptimized(arr, p + 1, hi);
            hi = p - 1;  /* tail call elimination */
        }
    }
}

