#include <stdio.h>
#include <string.h>

typedef struct {
    char name[20];
    int grade;
} Student;

/* Stable insertion sort (preserves order of equal grades) */
void stableSort(Student arr[], int n) {
    for (int i = 1; i < n; i++) {
        Student key = arr[i];
        int j = i - 1;
        /* > (not >=) ensures stability */
        while (j >= 0 && arr[j].grade > key.grade) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
}

/* Unstable selection sort (may change relative order) */
void unstableSort(Student arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        int min = i;
        for (int j = i + 1; j < n; j++)
            if (arr[j].grade < arr[min].grade)
                min = j;
        if (min != i) {
            Student temp = arr[i];
            arr[i] = arr[min];
            arr[min] = temp;
        }
    }
}

int main(void) {
    Student s1[] = {
        {"Alice", 2}, {"Bob", 1}, {"Carol", 2}, {"Dave", 1}
    };
    Student s2[] = {
        {"Alice", 2}, {"Bob", 1}, {"Carol", 2}, {"Dave", 1}
    };

    stableSort(s1, 4);
    printf("Stable sort:\n");
    for (int i = 0; i < 4; i++)
        printf("  %s (grade %d)\n", s1[i].name, s1[i].grade);
    /* Bob(1), Dave(1), Alice(2), Carol(2) -- original order preserved */

    unstableSort(s2, 4);
    printf("Unstable sort:\n");
    for (int i = 0; i < 4; i++)
        printf("  %s (grade %d)\n", s2[i].name, s2[i].grade);
    /* May give Dave(1), Bob(1) -- relative order not guaranteed */

    return 0;
}

