void stableInsertionSort(int arr[], int n) {
    for (int i = 1; i < n; i++) {
        int key = arr[i], j = i - 1;
        while (j >= 0 && arr[j] > key) {  /* > not >= for stability */
            arr[j+1] = arr[j];
            j--;
        }
        arr[j+1] = key;
    }
}

