/* Counting sort for non-negative integers */
void countingSort(int arr[], int n) {
    if (n <= 1) return;

    /* Find range */
    int max = arr[0], min = arr[0];
    for (int i = 1; i < n; i++) {
        if (arr[i] > max) max = arr[i];
        if (arr[i] < min) min = arr[i];
    }

    int range = max - min + 1;
    int *count = (int *)calloc(range, sizeof(int));
    int *output = (int *)malloc(n * sizeof(int));

    /* Count occurrences */
    for (int i = 0; i < n; i++)
        count[arr[i] - min]++;

    /* Prefix sum */
    for (int i = 1; i < range; i++)
        count[i] += count[i - 1];

    /* Build output (iterate backwards for stability) */
    for (int i = n - 1; i >= 0; i--) {
        output[count[arr[i] - min] - 1] = arr[i];
        count[arr[i] - min]--;
    }

    /* Copy back */
    for (int i = 0; i < n; i++)
        arr[i] = output[i];

    free(count);
    free(output);
}

void printArray(int arr[], int n) {
    for (int i = 0; i < n; i++)
        printf("%d ", arr[i]);
    printf("\n");
}

int main(void) {
    int arr[] = {4, 2, 2, 8, 3, 3, 1};
    int n = sizeof(arr) / sizeof(arr[0]);

    printf("Before: ");
    printArray(arr, n);

    countingSort(arr, n);

    printf("After:  ");
    printArray(arr, n);  /* 1 2 2 3 3 4 8 */

    /* Works with negative numbers too */
    int arr2[] = {-5, -2, 3, 0, -1, 2};
    int n2 = 6;
    countingSort(arr2, n2);
    printf("Neg:    ");
    printArray(arr2, n2);  /* -5 -2 -1 0 2 3 */

    return 0;
}

