/* Hybrid approach: use insertion sort for small subarrays */
#define INSERTION_THRESHOLD 16

void insertionSort(int arr[], int lo, int hi) {
    for (int i = lo + 1; i <= hi; i++) {
        int key = arr[i], j = i - 1;
        while (j >= lo && arr[j] > key) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
}

void swap(int *a, int *b) { int t = *a; *a = *b; *b = t; }

int partition(int arr[], int lo, int hi) {
    /* Median-of-three pivot */
    int mid = lo + (hi - lo) / 2;
    if (arr[lo] > arr[mid]) swap(&arr[lo], &arr[mid]);
    if (arr[lo] > arr[hi]) swap(&arr[lo], &arr[hi]);
    if (arr[mid] > arr[hi]) swap(&arr[mid], &arr[hi]);
    swap(&arr[mid], &arr[hi - 1]);  /* pivot at hi-1 */
    int pivot = arr[hi - 1];
    int i = lo, j = hi - 1;
    while (1) {
        while (arr[++i] < pivot);
        while (arr[--j] > pivot);
        if (i >= j) break;
        swap(&arr[i], &arr[j]);
    }
    swap(&arr[i], &arr[hi - 1]);
    return i;
}

/* Hybrid quicksort: switches to insertion sort for small partitions */
void hybridSort(int arr[], int lo, int hi) {
    if (hi - lo < INSERTION_THRESHOLD) {
        insertionSort(arr, lo, hi);
        return;
    }
    int p = partition(arr, lo, hi);
    hybridSort(arr, lo, p - 1);
    hybridSort(arr, p + 1, hi);
}

int main(void) {
    int arr[] = {38, 27, 43, 3, 9, 82, 10, 15, 44, 2, 7, 1};
    int n = sizeof(arr) / sizeof(arr[0]);

    hybridSort(arr, 0, n - 1);

    for (int i = 0; i < n; i++)
        printf("%d ", arr[i]);
    printf("\n");  /* 1 2 3 7 9 10 15 27 38 43 44 82 */

    return 0;
}

