void swap(int *a, int *b) { int t = *a; *a = *b; *b = t; }

int partition(int arr[], int lo, int hi) {
    int pivot = arr[hi], i = lo - 1;
    for (int j = lo; j < hi; j++)
        if (arr[j] <= pivot)
            swap(&arr[++i], &arr[j]);
    swap(&arr[i + 1], &arr[hi]);
    return i + 1;
}

/* Find kth smallest element (0-indexed) using Quickselect: avg O(n) */
int quickselect(int arr[], int lo, int hi, int k) {
    if (lo == hi) return arr[lo];

    int pivotIdx = partition(arr, lo, hi);

    if (k == pivotIdx)
        return arr[k];
    else if (k < pivotIdx)
        return quickselect(arr, lo, pivotIdx - 1, k);
    else
        return quickselect(arr, pivotIdx + 1, hi, k);
}

/* Find kth largest: kth largest = (n-k)th smallest */
int findKthLargest(int arr[], int n, int k) {
    return quickselect(arr, 0, n - 1, n - k);
}

/* Search in rotated sorted array: O(log n) */
int searchRotated(int arr[], int n, int target) {
    int lo = 0, hi = n - 1;

    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;

        if (arr[mid] == target)
            return mid;

        /* Left half is sorted */
        if (arr[lo] <= arr[mid]) {
            if (target >= arr[lo] && target < arr[mid])
                hi = mid - 1;
            else
                lo = mid + 1;
        }
        /* Right half is sorted */
        else {
            if (target > arr[mid] && target <= arr[hi])
                lo = mid + 1;
            else
                hi = mid - 1;
        }
    }
    return -1;
}

